mapper.update:
update reservation_package
area_id = #{areaId}, package_name = #{packageName}, package_price = #{packagePrice}, status = #{status}, package_desc = #{packageDesc}, package_image = #{packageImage}, duration_hours = #{durationHours}, valid_days = #{validDays}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

mapper.select:
select p.id, p.area_id, a.name as area_name, p.package_name, coalesce(p.package_price, 0) as price, p.status, p.package_desc, p.package_image as image, p.duration_hours, p.valid_days, p.create_time, p.update_time from reservation_package p left join area a on p.area_id = a.id
and p.package_name like concat('%', #{packageName}, '%')
and p.area_id = #{areaId}
and p.status = #{status}
order by p.create_time desc

select count(p.id) from reservation_package p


        and p.package_name like concat('%', #{packageName}, '%')


        and p.area_id = #{areaId}


        and p.status = #{status}
